async (params, browser) => {
  // Open agent profile
  await browser.open(`${params.agent_url}`)

  // Wait for profile to load
  await browser.waitForSelector('[class*=\'agent\'], [class*=\'profile\'], h1', 15000)

  // Let page render
  await browser.wait(2000)

  // Scroll to load more
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Scroll further
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Extract agent profile
  const agent_data = await browser.evaluate(`const nameEl = document.querySelector('h1, [class*="agent-name"], [class*="profile-name"]'); const brokerEl = document.querySelector('[class*="brokerage"], [class*="broker-name"]'); const phoneEl = document.querySelector('[class*="phone"], a[href^="tel:"]'); const ratingEl = document.querySelector('[class*="rating"], [class*="stars"]'); const reviewCountEl = document.querySelector('[class*="review-count"], [class*="reviews"]'); const photoEl = document.querySelector('[class*="profile-photo"] img, [class*="agent-photo"] img, [class*="avatar"] img'); const bioEl = document.querySelector('[class*="bio"], [class*="about"], [class*="description"]'); const specialties = []; const specEls = document.querySelectorAll('[class*="specialty"] li, [class*="specialization"] li'); specEls.forEach(function(el) { specialties.push(el.textContent.trim()); }); const listings = []; const listingEls = document.querySelectorAll('[class*="listing-card"], [class*="property-card"]'); for (let i = 0; i < Math.min(listingEls.length, 10); i++) { const el = listingEls[i]; const addrEl = el.querySelector('[class*="address"], address'); const priceEl = el.querySelector('[class*="price"]'); const linkEl = el.querySelector('a'); listings.push({ address: addrEl ? addrEl.textContent.trim() : '', price: priceEl ? priceEl.textContent.trim() : '', url: linkEl ? linkEl.href : '' }); } const salesEl = document.querySelector('[class*="sales-count"], [class*="past-sales"]'); const activeListingsEl = document.querySelector('[class*="active-listings"], [class*="for-sale"]'); return { name: nameEl ? nameEl.textContent.trim() : '', brokerage: brokerEl ? brokerEl.textContent.trim() : '', phone: phoneEl ? phoneEl.textContent.trim() : '', rating: ratingEl ? ratingEl.textContent.trim() : '', review_count: reviewCountEl ? reviewCountEl.textContent.trim() : '', bio: bioEl ? bioEl.textContent.trim().substring(0, 1000) : '', photo: photoEl ? photoEl.getAttribute('src') : '', specialties: specialties.slice(0, 10), past_sales: salesEl ? salesEl.textContent.trim() : '', active_listings_count: activeListingsEl ? activeListingsEl.textContent.trim() : '', listings: listings, url: window.location.href }`)

  return agent_data
}
